+/**
+ * Run an agent until it completes. A delegate_task pauses the current agent,
+ * runs the requested agent, and invokes the current agent again with one
+ * correlated tool_result in its context.
+ */
+async function* executeAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+  streamAgentOutput: boolean,
+  streamProviderErrors: boolean,
+): AsyncGenerator<StreamResponse, AgentExecutionResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    const content = `Agent '${agentId}' not found or provider not available`;
+    // Missing agents are actionable protocol errors, including when requested
+    // from delegate_task.
+    yield { type: "error", error: content };
+    return { content, isError: true };
+  }
+
+  const context: ProviderContext[] = [];
+  let accumulatedText = "";
+  let toolSequence = 0;
+
+  while (true) {
+    const providerRequest: ProviderChatRequest = {
+      message: request.message,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      ...(context.length ? { context } : {}),
+    };
+    let delegatedThisInvocation = false;
+
+    try {
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "text") {
+          const content = response.content || "";
+          accumulatedText += content;
+          if (streamAgentOutput) yield* streamAgentResponse(response, agentId, request.sessionId);
+          continue;
+        }
+
+        if (response.type === "tool_use") {
+          const toolUseId = response.toolUseId || `delegate-${agentId}-${++toolSequence}`;
+          if (streamAgentOutput) yield streamToolUse(response, toolUseId, request.sessionId);
+
+          if (response.toolName !== "delegate_task") continue;
+
+          delegatedThisInvocation = true;
+          const input = (response.toolInput || {}) as DelegateTaskInput;
+          const targetAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+          const instructions = typeof input.instructions === "string" ? input.instructions : "";
+          let delegateResult: AgentExecutionResult;
+
+          if (!targetAgentId) {
+            delegateResult = { content: "delegate_task requires an agent_id", isError: true };
+          } else if (delegationPath.includes(targetAgentId)) {
+            const content = `Circular delegation detected: ${[...delegationPath, targetAgentId].join(" -> ")}`;
+            yield { type: "error", error: content };
+            delegateResult = { content, isError: true };
+          } else {
+            const delegatedRequest: ChatRequest = {
+              ...request,
+              message: instructions,
+            };
+            // Sub-agent provider errors are represented solely by the parent
+            // tool_result. Circular/missing-agent errors above remain stream
+            // errors as required by the chat protocol.
+            delegateResult = yield* executeAgentConversation(
+              targetAgentId,
+              delegatedRequest,
+              abortController,
+              debugMode,
+              [...delegationPath, targetAgentId],
+              false,
+              false,
+            );
+          }
+
+          const resultContent = delegateResult.isError
+            ? delegateResult.content
+            : delegateResult.content || EMPTY_SUB_AGENT_OUTPUT;
+          const toolResultContent = JSON.stringify({
+            type: "tool_result",
+            is_error: delegateResult.isError,
+            content: resultContent,
+            tool_use_id: toolUseId,
+          });
+
+          if (streamAgentOutput) {
+            yield {
+              type: "claude_json",
+              data: {
+                type: "user",
+                message: {
+                  content: [{
+                    type: "tool_result",
+                    tool_use_id: toolUseId,
+                    is_error: delegateResult.isError,
+                    content: toolResultContent,
+                  }],
+                },
