+        }
+
+        if (response.type === "error") {
+          const content = response.error || "Agent run failed";
+          if (streamProviderErrors) yield { type: "error", error: content };
+          return { content, isError: true };
+        }
+
+        if (response.type === "done") break;
+      }
+    } catch (error) {
+      const content = error instanceof Error ? error.message : String(error);
+      if (streamProviderErrors) yield { type: "error", error: content };
+      return { content, isError: true };
+    }
+
+    if (!delegatedThisInvocation) {
+      return { content: accumulatedText, isError: false };
+    }
