+    };
+  }
+  yield {
+    type: "claude_json",
+    data: { type: "assistant", content: response.content, model: response.metadata?.model },
+  };
+}
+
+function streamToolUse(response: ProviderResponse, toolUseId: string, sessionId?: string): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      message: {
+        content: [{
+          type: "tool_use",
+          id: toolUseId,
+          name: response.toolName,
+          input: response.toolInput || {},
+        }],
+      },
+      session_id: sessionId,
